import{_ as t,r as s,o as r,c as l,a as e,b as a,d as o,e as c}from"./app-25fa875f.js";const d={},i=e("h1",{id:"latex",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#latex","aria-hidden":"true"},"#"),a(" LaTeX")],-1),h=e("p",null,"Created by : Mr Dk.",-1),u=e("p",null,"2019 / 02 / 13 23:34",-1),_=e("p",null,"Ningbo, Zhejiang, China",-1),p=e("hr",null,null,-1),f=e("h2",{id:"about",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#about","aria-hidden":"true"},"#"),a(" About")],-1),b=e("p",null,"LaTeX（/ˈlɑːtɛx/，常被读作 /ˈlɑːtɛk/ 或 /ˈleɪtɛk/ ），排版时通常使用 LaTeX，是一种基于 TeX 的排版系统，由美国计算机科学家莱斯利·兰伯特在 20 世纪 80 年代初期开发，利用这种格式系统的处理，即使用户没有排版和程序设计的知识也可以充分发挥由 TeX 所提供的强大功能，不必一一亲自去设计或校对，能在几天，甚至几小时内生成很多具有书籍质量的印刷品。对于生成复杂表格和数学公式，这一点表现得尤为突出。因此它非常适用于生成高印刷质量的科技和数学、物理文档。这个系统同样适用于生成从简单的信件到完整书籍的所有其他种类的文档。",-1),x={href:"https://blog.csdn.net/shujuelin/article/details/79340373",target:"_blank",rel:"noopener noreferrer"},m=c(`<p>LaTeX 和 Web Page 的工作方式很类似，都由源文件（<code>.tex</code> 或 <code>.html</code>）经由引擎（TeX 或 Browser）渲染产生最终效果（<code>.pdf</code> 文件或页面）。在 Web 中，规范的写法是在 <code>.html</code> 文件中写入页面结构和内容，由 <code>.css</code> 文件控制页面生成的样式；在 LaTeX 中，在 <code>.tex</code> 中写入文档的结构和内容，由 <code>.cls</code>、<code>.sty</code> 文件控制样式。从而做到内容与样式分离。</p><h2 id="installation-configuration" tabindex="-1"><a class="header-anchor" href="#installation-configuration" aria-hidden="true">#</a> Installation &amp; Configuration</h2><p>别废话了，咱就是说，在 Linux 上安装最便捷，编译效率也最高。在 VSCode 中使用 Remote-WSL 或 Remote-SSH 插件连上 Linux 主机，用下面的命令一键安装后，再为 VSCode 安装上 LaTeX Workshop 插件就可以开箱使用了：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">apt</span> <span class="token function">install</span> texlive-full
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="references" tabindex="-1"><a class="header-anchor" href="#references" aria-hidden="true">#</a> References</h2>`,5),g={href:"https://blog.triplez.cn/build-a-great-latex-workflow/",target:"_blank",rel:"noopener noreferrer"},k={href:"https://dowww.spencerwoo.com/3-vscode/3-5-latex.html",target:"_blank",rel:"noopener noreferrer"};function L(T,v){const n=s("ExternalLinkIcon");return r(),l("div",null,[i,h,u,_,p,f,b,e("p",null,[e("a",x,[a("一种不错的理解方式"),o(n)])]),m,e("p",null,[e("a",g,[a("Triple'Z's blog"),o(n)])]),e("p",null,[e("a",k,[a("Dev on Windows with WSL - LaTeX"),o(n)])])])}const w=t(d,[["render",L],["__file","LaTeX.html.vue"]]);export{w as default};
